#include <bits/stdc++.h>
#define endl "\n"
class TreeNode {
    int val;
    TreeNode*left;
    TreeNode*right;
public:
    TreeNode(int val=0, TreeNode* left=nullptr, TreeNode* right=nullptr) :
        val(val), left(left), right(right) {}
};
class Solution {
    int findLCA(TreeNode* root, int p, int q) {
        if (!root) return -1;
        if (root->val == p || root->val == q) return root->val;
        int left = findLCA(root->left, p, q);
        int right = findLCA(root->right, p, q);
        if (left != -1 && right != -1) return root->val;
        if (left != -1) return left;
        return right;
    }
};
int main() {
    std::ios_base::sync_with_stdio(0);
    cin.tie(0);
    cin.exceptions(std::cin.failbit);
    int n;
    cin >> n;
    std::vector<int>arr(n);
    for (int&i: arr) cin>>i;
    Solution sol;
    int p, q;
    cin>>p>>q;
    std::cout << sol.findLCA(nullptr, p, q) << std::endl;
    exit(0);
}
